boot.artifact:
// inferred-not-tested。custom element:import 即注册 <g-chess-board>
import 'https://cdn.jsdelivr.net/npm/gchessboard@1/+esm';
const b = document.createElement('g-chess-board');   // 铁律 4:JS 创建,不写声明式标签
b.setAttribute('fen', data.fen.split(' ')[0]); // 只喂 FEN 摆放段(完整/摆放皆可)
if (data.orientation) b.setAttribute('orientation', data.orientation);
b.style.maxWidth = '480px';
document.getElementById('board').appendChild(b);

boot.widget:
// 关键教材:widget sanitizer 禁声明式自定义标签 + 行内事件(铁律 4)⇒ 必须 createElement 挂载。
// gchessboard 内部自带 shadow root,样式自封闭 → ZF 安全,直接挂进我们的 shadowRoot 容器
import 'https://cdn.jsdelivr.net/npm/gchessboard@1/+esm';
const b = document.createElement('g-chess-board');
b.setAttribute('fen', data.fen.split(' ')[0]); // 只喂 FEN 摆放段(完整/摆放皆可)
b.style.maxWidth = '480px';
shadowRoot.appendChild(b);
